mapper.select:
select apt_cmplex_no
from mgmt_office
where mgmt_ofc_no = #{mgmtOfcNo}

select count(*)
from facility_contract fc
inner join partner p
on fc.partner_no = p.partner_no
inner join mgmt_office mo
on p.apt_cmplex_no = mo.apt_cmplex_no
where mo.mgmt_ofc_no = #{mgmtOfcNo}


    and fc.cont_ty_cd = #{contTyCd}



    and fc.partner_no = #{partnerNo}



    and fc.cont_target_cd = #{contTargetCd}



    and fc.cont_stts_cd = #{contSttsCd}



    and fc.cont_bgng_dt >= to_date(#{periodStartDt}, 'yyyy-mm-dd')



    and fc.cont_end_dt < to_date(#{periodEndDt}, 'yyyy-mm-dd') + 1



    and fc.cont_amt >= #{minContAmt}



    and fc.cont_amt <= #{maxContAmt}



    and (
    lower(fc.cont_nm) like '%' || lower(#{keyword}) || '%'
    or lower(fc.cont_no) like '%' || lower(#{keyword}) || '%'
    or lower(p.partner_nm) like '%' || lower(#{keyword}) || '%'
    or lower(p.partner_no) like '%' || lower(#{keyword}) || '%'
    or exists (
    select 1
    from facility_contract_target fct2
    inner join facility f2
    on fct2.facility_no = f2.facility_no
    where fct2.cont_no = fc.cont_no
    and lower(f2.facility_nm) like '%' || lower(#{keyword}) || '%'
    )
    )

select * from ( select rownum rn , a.* from ( select fc.cont_no , fc.facility_no , fc.partner_no , p.partner_nm , p.biz_ty_nm , fc.cont_nm , fc.bid_ty_cd , bid_ty.code_name as bid_ty_nm , fc.cont_dt , fc.cont_stts_cd , cont_stts.code_name as cont_stts_nm , fc.cont_amt , fc.pymt_dt , fc.cont_bgng_dt , fc.cont_end_dt , fc.cont_ty_cd , cont_ty.code_name as cont_ty_nm , fc.cont_target_cd , fc.cont_cn , fc.rmrk_cn , fc.reg_dt , fc.mdf_dt , fc.file_group_no , nvl(t.target_count, 0) as target_count , t.target_summary , nvl(af.file_count, 0) as file_count from facility_contract fc inner join partner p on fc.partner_no = p.partner_no inner join mgmt_office mo on p.apt_cmplex_no = mo.apt_cmplex_no left join common_code cont_ty on cont_ty.group_code_no = 'CONT_TY' and cont_ty.code_no_cd = fc.cont_ty_cd left join common_code bid_ty on bid_ty.group_code_no = 'BID_TY' and bid_ty.code_no_cd = fc.bid_ty_cd left join common_code cont_stts on cont_stts.group_code_no = 'CONTRACT_STTS' and cont_stts.code_no_cd = fc.cont_stts_cd left join ( select fct.cont_no , count(*) as target_count , min(f.facility_nm) as target_summary from facility_contract_target fct inner join facility f on fct.facility_no = f.facility_no group by fct.cont_no ) t on fc.cont_no = t.cont_no left join ( select file_group_no , count(*) as file_count from attach_file group by file_group_no ) af on fc.file_group_no = af.file_group_no where mo.mgmt_ofc_no = #{search.mgmtOfcNo}
and fc.cont_ty_cd = #{search.contTyCd}
and fc.partner_no = #{search.partnerNo}
and fc.cont_target_cd = #{search.contTargetCd}
and fc.cont_stts_cd = #{search.contSttsCd}
and fc.cont_bgng_dt >= to_date(#{search.periodStartDt}, 'yyyy-mm-dd')
and fc.cont_end_dt < to_date(#{search.periodEndDt}, 'yyyy-mm-dd') + 1
and fc.cont_amt >= #{search.minContAmt}
and fc.cont_amt <= #{search.maxContAmt}
and ( lower(fc.cont_nm) like '%' || lower(#{search.keyword}) || '%' or lower(fc.cont_no) like '%' || lower(#{search.keyword}) || '%' or lower(p.partner_nm) like '%' || lower(#{search.keyword}) || '%' or lower(p.partner_no) like '%' || lower(#{search.keyword}) || '%' or exists ( select 1 from facility_contract_target fct2 inner join facility f2 on fct2.facility_no = f2.facility_no where fct2.cont_no = fc.cont_no and lower(f2.facility_nm) like '%' || lower(#{search.keyword}) || '%' ) )
order by fc.reg_dt desc nulls last , nvl(fc.cont_bgng_dt, fc.reg_dt) desc , to_number(regexp_substr(fc.cont_no, '[0-9]+')) desc , fc.cont_no desc ) a where rownum <= #{pagingVO.endRow} ) where rn >= #{pagingVO.startRow}

select count(*) as total_cnt , sum( case when (fc.cont_end_dt is null or fc.cont_end_dt >= trunc(sysdate)) and nvl(fc.cont_stts_cd, 'ACTIVE') not in ('END', 'TERM') then 1 else 0 end ) as active_cnt , sum( case when fc.cont_end_dt is not null and fc.cont_end_dt >= trunc(sysdate) and fc.cont_end_dt < trunc(sysdate) + 31 and nvl(fc.cont_stts_cd, 'ACTIVE') not in ('END', 'TERM') then 1 else 0 end ) as expire_soon_cnt , sum( case when fc.cont_end_dt is not null and fc.cont_end_dt < trunc(sysdate) then 1 else 0 end ) as expired_cnt from facility_contract fc inner join partner p on fc.partner_no = p.partner_no inner join mgmt_office mo on p.apt_cmplex_no = mo.apt_cmplex_no where mo.mgmt_ofc_no = #{mgmtOfcNo}
and fc.cont_ty_cd = #{contTyCd}
and fc.partner_no = #{partnerNo}
and fc.cont_target_cd = #{contTargetCd}
and fc.cont_stts_cd = #{contSttsCd}
and fc.cont_bgng_dt >= to_date(#{periodStartDt}, 'yyyy-mm-dd')
and fc.cont_end_dt < to_date(#{periodEndDt}, 'yyyy-mm-dd') + 1
and fc.cont_amt >= #{minContAmt}
and fc.cont_amt <= #{maxContAmt}
and ( lower(fc.cont_nm) like '%' || lower(#{keyword}) || '%' or lower(fc.cont_no) like '%' || lower(#{keyword}) || '%' or lower(p.partner_nm) like '%' || lower(#{keyword}) || '%' or lower(p.partner_no) like '%' || lower(#{keyword}) || '%' or exists ( select 1 from facility_contract_target fct2 inner join facility f2 on fct2.facility_no = f2.facility_no where fct2.cont_no = fc.cont_no and lower(f2.facility_nm) like '%' || lower(#{keyword}) || '%' ) )

mapper.insert:
insert into facility_contract (
cont_no
, facility_no
, partner_no
, cont_nm
, bid_ty_cd
, cont_dt
, cont_stts_cd
, cont_amt
, pymt_dt
, cont_bgng_dt
, cont_end_dt
, cont_ty_cd
, cont_target_cd
, cont_cn
, rmrk_cn
, file_group_no
, reg_dt
) values (
#{contNo}
, #{facilityNo}
, #{partnerNo}
, #{contNm}
, #{bidTyCd}
, #{contDt}
, #{contSttsCd}
, #{contAmt}
, #{pymtDt}
, #{contBgngDt}
, #{contEndDt}
, #{contTyCd}
, #{contTargetCd}
, #{contCn}
, #{rmrkCn}
, #{fileGroupNo}
, sysdate
)

mapper.update:
update facility_contract
set facility_no = #{facilityNo}
, partner_no = #{partnerNo}
, cont_nm = #{contNm}
, bid_ty_cd = #{bidTyCd}
, cont_dt = #{contDt}
, cont_stts_cd = #{contSttsCd}
, cont_amt = #{contAmt}
, pymt_dt = #{pymtDt}
, cont_bgng_dt = #{contBgngDt}
, cont_end_dt = #{contEndDt}
, cont_ty_cd = #{contTyCd}
, cont_target_cd = #{contTargetCd}
, cont_cn = #{contCn}
, rmrk_cn = #{rmrkCn}
, file_group_no = #{fileGroupNo}
, mdf_dt = sysdate
where cont_no = #{contNo}

